    const P = new Array(N + 1).fill(0);
    for (let i = 0; i < N; i++) {
        P[i + 1] = P[i] + (nums[i] % 2 === 0 ? 1 : 0);
    }

    const results: number[] = [];

    // Max possible required Y (X/2): k_max + N_max ~ 10^9 + 10^5
    // We use a safe upper bound for the binary search.
    const MAX_Y = 2 * 10**9 + 100005; 

    for (const [l, r, k] of queries) {

        // Check function: Does the k-th remaining element <= 2Y?
        // i.e., Is the count of remaining even numbers <= 2Y at least k?
        const check = (Y: number): boolean => {
            if (Y === 0) return false; 

            const V = 2 * Y; // Target value 2Y

            // Find j: index of the first element in nums strictly greater than V
            // Elements nums[0...j-1] are <= V
            const j = upperBound(nums, V);

            // The relevant indices are [l, r] intersected with [0, j-1].
            // Effective range end index r' = min(r, j-1)
            const r_prime = Math.min(r, j - 1);

            if (l > r_prime) {
                // No elements in the range [l, r] are <= V
                return Y >= k; // Only true if Y >= k, meaning all Y elements (if no removals) satisfy it. Since C=0, we check Y >= k.
            }

            // Count of removed even numbers <= V in range [l, r_prime]
            // Count = P[r_prime + 1] - P[l]
            const C = P[r_prime + 1] - P[l];

            // Total even numbers <= V is Y (since V=2Y)
            // Remaining count = Total - Removed
            const remaining_count = Y - C;

            return remaining_count >= k;
        };

        // 2. Binary Search for the minimum Y such that check(Y) is true
        let low = 1;
        let high = MAX_Y;
        let ans_Y = MAX_Y;

        while (low <= high) {
            // Using standard JS number arithmetic is safe here as MAX_Y < 2^53
            const mid = Math.floor((low + high) / 2);

            if (check(mid)) {
                ans_Y = mid;
                high = mid - 1; // Try for a smaller Y
            } else {
                low = mid + 1; // Need a larger Y
            }
        }

        // The result is 2 * ans_Y
        results.push(2 * ans_Y);
    }

    return results;
}
